fn test_rrf_merge_complex() {
        let vector = vec![
            ("1".to_string(), 0.9),
            ("2".to_string(), 0.8),
            ("3".to_string(), 0.7),
        ];
        let bm25 = vec![("3".to_string(), 0.9), ("1".to_string(), 0.8)];

        let results = rrf_merge(&vector, &bm25, &[], 0.5, 0.5, 0.0, 10);

        // Item 1 rank: vector=0, bm25=1. Score = 0.5/(60+0+1) + 0.5/(60+1+1)
        // Item 3 rank: vector=2, bm25=0. Score = 0.5/(60+2+1) + 0.5/(60+0+1)

        assert_eq!(results[0].0, "1"); // Item 1 should be first because rank 0 + rank 1 is better than rank 2 + rank 0
        assert_eq!(results[1].0, "3");
        assert_eq!(results[2].0, "2");
    }

pub async fn search_code(
    state: &Arc<AppState>,
    params: SearchCodeParams,
) -> anyhow::Result<CallToolResult> {
    crate::ensure_embedding_ready!(state);

    let SearchCodeParams {
        query,
        project_id,
        limit,
    } = params;
    let project_id = normalize_project_id(project_id);

    let mut is_partial = false;
    let mut indexing_message = None;

    let mut project_status = None;
    if let Some(ref project_id) = project_id {
        if let Ok(Some(status)) = state.storage.get_index_status(project_id).await {
            if status.status == crate::types::IndexState::Indexing
                || status.status == crate::types::IndexState::EmbeddingPending
            {
                is_partial = true;
                indexing_message = Some(format!(
                    "Indexing in progress ({}/{} files). Results may be incomplete.",
                    status.indexed_files, status.total_files
                ));
            }
            project_status = Some(status);
        }
    }

    let query_embedding = state.embedding.embed(&query).await?;

    let limit = normalize_limit(limit);

    // Run vector search and BM25 in parallel for robust results.
    // Previously BM25 was only a fallback — degenerate vectors masked BM25 entirely.
    let project_id = project_id.as_deref();
    let (vector_results, bm25_results) = tokio::join!(
        async {
            match state
                .storage
                .vector_search_code(&query_embedding, project_id, limit)
                .await
            {
                Ok(results) => {
                    tracing::debug!(hits = results.len(), "search_code: vector search completed");
                    results
                }
                Err(e) => {
                    tracing::warn!(error = %e, "search_code: vector search failed, falling back to empty");
                    Vec::new()
                }
            }
        },
        async {
            state
                .code_search
                .search(&query, project_id, limit, state.storage.as_ref())
                .await
        }
    );

    // Merge: vector results first, then BM25 results not already present.
    // This gives vector priority in ranking while ensuring BM25 fills gaps.
    use std::collections::HashSet;
    let mut seen_ids: HashSet<String> = HashSet::new();
    let mut merged = Vec::with_capacity(limit);

    for r in &vector_results {
        if seen_ids.insert(r.id.clone()) {
            merged.push(json!({
                "id": r.id,
                "file_path": r.file_path,
                "content": r.content,
                "language": r.language,
                "start_line": r.start_line,
                "end_line": r.end_line,
                "chunk_type": r.chunk_type,
                "name": r.name,
                "context_path": r.context_path,
                "score": r.score,
                "source": "vector"
            }));
        }
        if merged.len() >= limit {
            break;
        }
    }

    for r in &bm25_results {
        if merged.len() >= limit {
            break;
        }
        if seen_ids.insert(r.id.clone()) {
            merged.push(json!({
                "id": r.id,
                "file_path": r.file_path,
                "content": r.content,
                "language": r.language,
                "start_line": r.start_line,
                "end_line": r.end_line,
                "chunk_type": r.chunk_type,
                "name": r.name,
                "context_path": r.context_path,
                "score": r.score,
                "source": "bm25"
            }));
        }
    }

    Ok(success_json(json!({
        "results": merged,
        "count": merged.len(),
        "summary": summary_collection_response(
            "collection",
            merged.len(),
            Some(merged.len()),
            is_partial,
            indexing_message.clone(),
        ),
        "query": query,
        "contract": code_search_contract_json(project_id, project_status.as_ref()),
        "vector_hits": vector_results.len(),
        "bm25_hits": bm25_results.len(),
        "is_partial": is_partial,
        "message": indexing_message
    })))
}

async fn tool_descriptions_and_required_params_remain_compatible() {
        let ctx = TestContext::new().await;
        let server = MemoryMcpServer::new(ctx.state.clone());
        let tools_json: Vec<Value> = server
            .tool_router
            .list_all()
            .iter()
            .map(|tool| serde_json::to_value(tool).expect("tool serializes"))
            .collect();

        let get_tool = |name: &str| {
            tools_json
                .iter()
                .find(|tool| tool.get("name").and_then(Value::as_str) == Some(name))
                .expect("tool must exist")
        };

        let recall_code = get_tool("recall_code");
        let recall_code_desc = recall_code
            .get("description")
            .and_then(Value::as_str)
            .unwrap_or_default();
        assert!(recall_code_desc.contains("Hybrid code retrieval"));
        let recall_code_required = schema_value(recall_code)
            .get("required")
            .and_then(Value::as_array)
            .cloned()
            .unwrap_or_default();
        assert!(recall_code_required
            .iter()
            .any(|value| value.as_str() == Some("query")));

        let search_symbols = get_tool("search_symbols");
        let search_symbols_desc = search_symbols
            .get("description")
            .and_then(Value::as_str)
            .unwrap_or_default();
        assert!(search_symbols_desc.contains("by-name") || search_symbols_desc.contains("lookup"));

        let symbol_graph = get_tool("symbol_graph");
        let symbol_graph_desc = symbol_graph
            .get("description")
            .and_then(Value::as_str)
            .unwrap_or_default();
        assert!(symbol_graph_desc.contains("symbol_id"));
        let symbol_graph_required = schema_value(symbol_graph)
            .get("required")
            .and_then(Value::as_array)
            .cloned()
            .unwrap_or_default();
        assert!(symbol_graph_required
            .iter()
            .any(|value| value.as_str() == Some("symbol_id")));
        assert!(symbol_graph_required
            .iter()
            .any(|value| value.as_str() == Some("action")));

        let project_info = get_tool("project_info");
        let project_info_desc = project_info
            .get("description")
            .and_then(Value::as_str)
            .unwrap_or_default();
        assert!(project_info_desc.contains("status") || project_info_desc.contains("indexing"));
        let project_info_required = schema_value(project_info)
            .get("required")
            .and_then(Value::as_array)
            .cloned()
            .unwrap_or_default();
        assert!(project_info_required
            .iter()
            .any(|value| value.as_str() == Some("action")));

        let recall = get_tool("recall");
        let recall_desc = recall
            .get("description")
            .and_then(Value::as_str)
            .unwrap_or_default();
        assert!(recall_desc.contains("Hybrid memory retrieval") || recall_desc.contains("fusion"));

        let search_memory = get_tool("search_memory");
        let search_memory_desc = search_memory
            .get("description")
            .and_then(Value::as_str)
            .unwrap_or_default();
        assert!(search_memory_desc.contains("memory"));
        let search_memory_required = schema_value(search_memory)
            .get("required")
            .and_then(Value::as_array)
            .cloned()
            .unwrap_or_default();
        assert!(search_memory_required
            .iter()
            .any(|value| value.as_str() == Some("query")));

        let how_to_use = get_tool("how_to_use");
        let how_to_use_desc = how_to_use
            .get("description")
            .and_then(Value::as_str)
            .unwrap_or_default();
        assert!(how_to_use_desc.contains("Meta-help") || how_to_use_desc.contains("meta-help"));
    }

mod tests {
    use super::*;

    #[test]
    fn test_rrf_merge_empty() {
        let results = rrf_merge(&[], &[], &[], 0.4, 0.15, 0.45, 10);
        assert!(results.is_empty());
    }

    #[test]
    fn test_rrf_merge_single_source() {
        let vector = vec![
            ("a".to_string(), 0.9),
            ("b".to_string(), 0.8),
            ("c".to_string(), 0.7),
        ];
        let results = rrf_merge(&vector, &[], &[], 0.4, 0.15, 0.45, 10);

        assert_eq!(results.len(), 3);
        assert_eq!(results[0].0, "a");
        assert!(results[0].1.vector_score > 0.0);
        assert_eq!(results[0].1.bm25_score, 0.0);
    }

    #[test]
    fn test_rrf_merge_multiple_sources() {
        let vector = vec![("a".to_string(), 0.9), ("b".to_string(), 0.8)];
        let bm25 = vec![("b".to_string(), 0.95), ("c".to_string(), 0.7)];
        let results = rrf_merge(&vector, &bm25, &[], 0.4, 0.15, 0.45, 10);
        assert_eq!(results.len(), 3);
        let b_result = results.iter().find(|(id, _)| id == "b").unwrap();
        assert!(b_result.1.vector_score > 0.0);
        assert!(b_result.1.bm25_score > 0.0);
    }

    #[test]
    fn test_rrf_merge_complex() {
        let vector = vec![
            ("1".to_string(), 0.9),
            ("2".to_string(), 0.8),
            ("3".to_string(), 0.7),
        ];
        let bm25 = vec![("3".to_string(), 0.9), ("1".to_string(), 0.8)];

        let results = rrf_merge(&vector, &bm25, &[], 0.5, 0.5, 0.0, 10);

        // Item 1 rank: vector=0, bm25=1. Score = 0.5/(60+0+1) + 0.5/(60+1+1)
        // Item 3 rank: vector=2, bm25=0. Score = 0.5/(60+2+1) + 0.5/(60+0+1)

        assert_eq!(results[0].0, "1"); // Item 1 should be first because rank 0 + rank 1 is better than rank 2 + rank 0
        assert_eq!(results[1].0, "3");
        assert_eq!(results[2].0, "2");
