            .iter()
            .zip(new_scores.iter())
            .map(|(a, b)| (a - b).abs())
            .sum();

        scores = new_scores;

        if diff < tolerance {
            break;
        }
    }

    graph
        .node_indices()
        .map(|idx| (idx, scores[idx.index()]))
        .collect()
